// EDTMRS - Live Alert Popup Notification
import React, { useEffect } from 'react';

export default function AlertPopup({ alert, onClose }) {
  useEffect(() => {
    const timer = setTimeout(onClose, 8000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const severityColor = {
    critical: 'border-red-500 bg-red-500/10',
    high:     'border-orange-500 bg-orange-500/10',
    medium:   'border-yellow-500 bg-yellow-500/10',
    safe:     'border-emerald-500 bg-emerald-500/10',
  }[alert.risk_level] || 'border-blue-500 bg-blue-500/10';

  const iconColor = {
    critical: 'text-red-400',
    high:     'text-orange-400',
    medium:   'text-yellow-400',
    safe:     'text-emerald-400',
  }[alert.risk_level] || 'text-blue-400';

  return (
    <div className={`flex items-start gap-3 p-4 rounded-xl border backdrop-blur-sm shadow-2xl w-96 ${severityColor} animate-slide-in`}>
      <span className={`text-xl mt-0.5 ${iconColor}`}>⚠</span>
      <div className="flex-1 min-w-0">
        <div className="flex items-center justify-between mb-1">
          <span className={`text-xs font-bold uppercase tracking-wider ${iconColor}`}>
            {alert.risk_level} Risk Device
          </span>
          <button onClick={onClose} className="text-gray-500 hover:text-white text-sm leading-none">✕</button>
        </div>
        <div className="text-white text-sm font-medium truncate">{alert.device_name || 'USB Device'}</div>
        <div className="text-gray-400 text-xs mt-0.5">
          Host: <span className="text-gray-300">{alert.hostname}</span>
        </div>
        {alert.serial_number && alert.serial_number !== 'unknown' && (
          <div className="text-gray-500 text-[10px] mt-0.5 font-mono truncate">S/N: {alert.serial_number}</div>
        )}
      </div>
    </div>
  );
}
